/**
 * CreateQuizSkill - Save quiz problems to database
 *
 * Persists quiz questions generated by QuizGenerateSkill or other sources.
 * Associates quizzes with source content (books, URLs, chats).
 */

const BaseSkill = require('../BaseSkill');

class CreateQuizSkill extends BaseSkill {
  static get name() {
    return 'create_quiz';
  }

  static get description() {
    return 'Save quiz problems to the database. Associates quizzes with their source content for later review.';
  }

  static get parameters() {
    return {
      quiz: {
        type: 'array',
        description:
          'Array of quiz questions to save. Each should have question, options, and answer.',
      },
      sourceKey: {
        type: 'string',
        description: 'ID of source content (book ID, URL, chat ID)',
      },
      sourceType: {
        type: 'string',
        enum: ['book', 'web', 'chat', 'manual'],
        default: 'manual',
        description: 'Type of content source',
      },
    };
  }

  static get requiredParams() {
    return ['quiz'];
  }

  static get category() {
    return 'data';
  }

  /**
   * Check if quiz creation is available
   */
  static isAvailable(context) {
    const quizManager =
      context.quizManager || context.services?.quizManager;
    return !!quizManager;
  }

  async execute({ quiz, sourceKey = '', sourceType = 'manual' }) {
    const quizManager =
      this.context.quizManager || this.context.services?.quizManager;
    const token = this.context.token;

    if (!quizManager) {
      throw new Error('Quiz manager not available');
    }

    if (!token) {
      throw new Error('Authentication token required');
    }

    if (!Array.isArray(quiz) || quiz.length === 0) {
      throw new Error('Quiz array is empty or invalid');
    }

    const savedIds = [];
    const errors = [];

    // Save each quiz problem
    for (let i = 0; i < quiz.length; i++) {
      const problem = quiz[i];

      try {
        const normalizedProblem = this.normalizeProblem(
          problem,
          sourceKey,
          sourceType,
        );

        let result;
        if (quizManager.createQuizProblem) {
          result = quizManager.createQuizProblem(normalizedProblem, token);
        } else if (quizManager.create) {
          result = await quizManager.create(normalizedProblem, token);
        } else {
          throw new Error('Quiz manager does not support quiz creation');
        }

        if (result && result.id) {
          savedIds.push(result.id);
        } else {
          errors.push({ index: i, error: 'No ID returned' });
        }
      } catch (e) {
        console.error(`Error saving quiz problem ${i}:`, e);
        errors.push({ index: i, error: e.message });
      }
    }

    this.logExecution(
      { questionCount: quiz.length, sourceType, sourceKey: !!sourceKey },
      { savedCount: savedIds.length, errorCount: errors.length },
    );

    const allSaved = errors.length === 0;
    const message = allSaved
      ? `Successfully saved ${savedIds.length} quiz problems`
      : `Saved ${savedIds.length} of ${quiz.length} problems (${errors.length} errors)`;

    return {
      savedCount: savedIds.length,
      quizIds: savedIds,
      sourceKey,
      sourceType,
      errors: errors.length > 0 ? errors : undefined,
      message,
      success: allSaved,
    };
  }

  /**
   * Normalize a quiz problem to the expected format
   */
  normalizeProblem(problem, sourceKey, sourceType) {
    // Ensure options exist and are properly formatted
    const options = problem.options || {};
    const normalizedOptions = {
      optionA: options.optionA || options.A || options.a || '',
      optionB: options.optionB || options.B || options.b || '',
      optionC: options.optionC || options.C || options.c || '',
      optionD: options.optionD || options.D || options.d || '',
    };

    // Normalize answer to uppercase letter
    let answer = (problem.answer || 'A').toString().toUpperCase();
    if (answer.startsWith('OPTION')) {
      answer = answer.replace('OPTION', '');
    }
    if (!['A', 'B', 'C', 'D'].includes(answer)) {
      answer = 'A';
    }

    return {
      question: problem.question || '',
      options: normalizedOptions,
      answer,
      sourceKey: sourceKey || '',
      sourceType: sourceType || 'manual',
      myChoice: '', // User's choice (filled in when answering)
      correct: 0, // Whether user answered correctly (0 = not answered)
    };
  }
}

module.exports = CreateQuizSkill;
